using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tool instances ---
var notepad = new ResearchNotepad();

// --- Build the agent ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            return WebSearchTool.SearchAsync(query);
        },
        "web_search",
        "Searches the web for information on a given query. Returns a list of result snippets with titles and URLs."),

    AIFunctionFactory.Create(
        ([Description("A concise note to save from a search result")] string note,
         [Description("The source URL for attribution")] string source) =>
        {
            notepad.AddNote(note, source);
            return $"Note saved. You now have {notepad.Count} note(s).";
        },
        "save_note",
        "Saves a research note with its source URL for later use in the summary."),

    AIFunctionFactory.Create(
        () =>
        {
            var notes = notepad.GetNotes();
            return notes.Count == 0
                ? "No notes saved yet."
                : string.Join("\n", notes.Select((n, i) => $"[{i + 1}] {n.Note} (source: {n.Source})"));
        },
        "get_notes",
        "Retrieves all saved research notes with their source URLs."),
};

var agent = chatClient.AsAIAgent(
    instructions: """
        You are a research assistant. When given a topic:
        1. Use web_search to find relevant, recent information (perform 2-3 searches with different angles).
        2. Use save_note to record the most important findings with source URLs.
        3. Use get_notes to review what you've collected.
        4. Produce a well-structured summary with key findings, organized by theme, with source attribution.
        Be thorough but concise. Always cite your sources.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings",
    tools: tools);

// --- Run the agent ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent               ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "";
    if (string.IsNullOrEmpty(topic))
    {
        Console.WriteLine("No topic provided. Exiting.");
        return;
    }
}

Console.WriteLine($"\nResearching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    options: runOptions);

Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
Console.WriteLine(response.Text);
Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

// --- Tool implementations ---

/// <summary>Simulated web search tool using Bing search via HttpClient.</summary>
static class WebSearchTool
{
    private static readonly HttpClient s_httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(10),
    };

    public static async Task<string> SearchAsync(string query)
    {
        try
        {
            // Use DuckDuckGo HTML endpoint as a free search source
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var html = await s_httpClient.GetStringAsync(url);

            // Parse result snippets from the HTML response
            var results = ParseSearchResults(html);

            return results.Count == 0
                ? "No results found."
                : string.Join("\n\n", results.Select(r =>
                    $"**{r.Title}**\n{r.Snippet}\nURL: {r.Url}"));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseSearchResults(string html)
    {
        var results = new List<SearchResult>();

        // Parse DuckDuckGo HTML results
        var snippetParts = html.Split("class=\"result__body\"",
            StringSplitOptions.RemoveEmptyEntries);

        foreach (var part in snippetParts.Skip(1).Take(5))
        {
            var title = ExtractBetween(part, "class=\"result__a\"", "</a>") ?? "";
            title = StripHtml(title).Trim();

            var snippet = ExtractBetween(part, "class=\"result__snippet\"", "</a>") ?? "";
            snippet = StripHtml(snippet).Trim();

            var urlMatch = ExtractBetween(part, "class=\"result__url\"", "</a>") ?? "";
            urlMatch = StripHtml(urlMatch).Trim();
            if (!urlMatch.StartsWith("http"))
                urlMatch = "https://" + urlMatch;

            if (!string.IsNullOrWhiteSpace(title))
            {
                results.Add(new SearchResult(title, snippet, urlMatch));
            }
        }

        return results;
    }

    private static string? ExtractBetween(string text, string startMarker, string endMarker)
    {
        var startIdx = text.IndexOf(startMarker, StringComparison.Ordinal);
        if (startIdx < 0) return null;

        // Skip past the tag's closing '>'
        var afterStart = text.IndexOf('>', startIdx + startMarker.Length);
        if (afterStart < 0) return null;
        afterStart++;

        var endIdx = text.IndexOf(endMarker, afterStart, StringComparison.Ordinal);
        if (endIdx < 0) return null;

        return text[afterStart..endIdx];
    }

    private static string StripHtml(string html)
    {
        // Remove HTML tags and decode common entities
        var text = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", "");
        text = text.Replace("&amp;", "&")
                   .Replace("&lt;", "<")
                   .Replace("&gt;", ">")
                   .Replace("&quot;", "\"")
                   .Replace("&#x27;", "'")
                   .Replace("&nbsp;", " ");
        return text.Trim();
    }

    record SearchResult(string Title, string Snippet, string Url);
}

